const user = {
  name: 'Ada',
  regular() { return this && this.name; },
  arrow: () => (typeof self !== 'undefined' ? 'lexical(no own this)' : 'n/a'),
};

console.log(user.regular());        // 'Ada' (method call)
const detached = user.regular;
console.log(detached());            // undefined (plain call, strict)
console.log(user.regular.call({ name: 'Grace' })); // 'Grace'

const animal = { speak() { return this.sound; } };
const dog = Object.create(animal);
dog.sound = 'woof';

console.log(dog.speak());                       // 'woof' (found on animal)
console.log(dog.hasOwnProperty('speak'));       // false (inherited)
console.log(Object.getPrototypeOf(dog) === animal); // true

animal.speak = function () { return 'overridden:' + this.sound; };
console.log(dog.speak());                       // 'overridden:woof'

const wait = (ms, v) => new Promise(r => setTimeout(() => r(v), ms));

async function run() {
  const start = Date.now();
  // parallel: both timers run together
  const [a, b] = await Promise.all([wait(50, 'A'), wait(50, 'B')]);
  console.log(a, b, 'in ~', Date.now() - start, 'ms');
}
run();

