function* naturals() {
  let n = 1;
  while (true) yield n++;        // infinite, but lazy
}
const it = naturals();
console.log(it.next().value, it.next().value); // 1 2

function* take(gen, k) {
  for (const v of gen) { if (k-- <= 0) return; yield v; }
}
console.log([...take(naturals(), 5)]); // [1,2,3,4,5]

function memoize(fn) {
  const cache = new Map();
  return (...args) => {
    const key = JSON.stringify(args);
    if (cache.has(key)) { console.log('hit', key); return cache.get(key); }
    const val = fn(...args);
    cache.set(key, val);
    return val;
  };
}
const slowSquare = memoize(n => n * n);
console.log(slowSquare(8)); // 64 (computed)
console.log(slowSquare(8)); // hit [8] -> 64 (cached)

